   396→                  <span>{name === 'root' ? 'Root' : name}</span>
   397→                  <span className="opacity-60">({count})</span>
   398→                </div>
   399→              ))}
   400→            </div>
   401→          )}
   402→        </div>
   403→
   404→        {/* Instructions */}
   405→        <div className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
