     1→/**
     2→ * Graph Canvas Component
     3→ * Interactive D3 force-directed graph visualization
     4→ */
     5→
     6→import { useEffect, useRef, useState } from 'react';
     7→import * as d3 from 'd3';
     8→import type { GraphData } from '../../utils/graphDataProcessor';
     9→import {
    10→  createForceSimulation,
    11→  stopSimulation,
    12→} from '../../utils/graphSimulation';
    13→import {
    14→  calculateAllLinkStrengths,
    15→  getEdgeKey,
    16→  getLinkOpacity,
    17→} from '../../utils/graphLinkStrength';
    18→import type { SearchResult } from '../../utils/graphSearch';
    19→import { getSearchHighlightStyle } from '../../utils/graphSearch';
    20→
    21→interface GraphCanvasProps {
    22→  data: GraphData;
    23→  onNodeClick?: (nodeId: string, nodeType: 'note' | 'tag') => void;
    24→  onNodeDoubleClick?: (nodeId: string, nodeType: 'note' | 'tag') => void;
    25→  focusNodeId?: string | null;
    26→  width?: number;
    27→  height?: number;
    28→  /** Search result for highlighting */
    29→  searchResult?: SearchResult | null;
    30→  /** Whether to show link strength visualization */
    31→  showLinkStrength?: boolean;
    32→  /** Set of orphan node IDs */
    33→  orphanIds?: Set<string>;
    34→}
    35→
    36→export function GraphCanvas({
    37→  data,
    38→  onNodeClick,
    39→  onNodeDoubleClick,
    40→  focusNodeId,
    41→  width = 1200,
    42→  height = 800,
    43→  searchResult = null,
    44→  showLinkStrength = false,
    45→  orphanIds = new Set(),
    46→}: GraphCanvasProps) {
    47→  const svgRef = useRef<SVGSVGElement>(null);
    48→  const [isSimulating, setIsSimulating] = useState(true);
    49→
    50→  useEffect(() => {
    51→    if (!svgRef.current || data.nodes.length === 0) return;
    52→
    53→    // Calculate link strengths for visualization
    54→    const linkStrengthMap = showLinkStrength
    55→      ? calculateAllLinkStrengths(data.edges)
    56→      : new Map();
    57→
    58→    const svg = d3.select(svgRef.current);
    59→    svg.selectAll('*').remove(); // Clear previous render
    60→
    61→    // Create container group for zoom/pan
    62→    const g = svg.append('g');
    63→
    64→    // Setup zoom behavior
    65→    const zoom = d3
    66→      .zoom<SVGSVGElement, unknown>()
    67→      .scaleExtent([0.1, 4])
    68→      .on('zoom', (event) => {
    69→        g.attr('transform', event.transform);
    70→      });
    71→
    72→    svg.call(zoom);
    73→
    74→    // Create simulation
    75→    const simulation = createForceSimulation(data.nodes, data.edges, width, height);
    76→
    77→    // Create arrow marker for directed edges
    78→    svg
    79→      .append('defs')
    80→      .append('marker')
    81→      .attr('id', 'arrowhead')
    82→      .attr('viewBox', '-0 -5 10 10')
    83→      .attr('refX', 20) // Position at end of line
    84→      .attr('refY', 0)
    85→      .attr('orient', 'auto')
    86→      .attr('markerWidth', 6)
    87→      .attr('markerHeight', 6)
    88→      .append('svg:path')
    89→      .attr('d', 'M 0,-5 L 10 ,0 L 0,5')
    90→      .attr('fill', 'var(--border-light)')
    91→      .attr('class', 'dark:fill-border-dark');
    92→
    93→    // Create links
    94→    const link = g
    95→      .append('g')
    96→      .attr('class', 'links')
    97→      .selectAll('line')
    98→      .data(data.edges)
    99→      .join('line')
   100→      .attr('stroke', (d) => {
   101→        if (showLinkStrength) {
   102→          const key = getEdgeKey(d.source as string, d.target as string);
   103→          const strengthInfo = linkStrengthMap.get(key);
   104→          if (strengthInfo?.isTagBased) {
   105→            return 'var(--border-light)';
   106→          }
   107→        }
   108→        return d.type === 'backlink' ? 'var(--accent-cyan)' : 'var(--border-light)';
   109→      })
   110→      .attr('stroke-opacity', (d) => {
   111→        if (showLinkStrength) {
   112→          const key = getEdgeKey(d.source as string, d.target as string);
   113→          const strengthInfo = linkStrengthMap.get(key);
   114→          if (strengthInfo) {
   115→            return getLinkOpacity(strengthInfo);
   116→          }
   117→        }
   118→        return d.type === 'backlink' ? 0.6 : 0.4;
   119→      })
   120→      .attr('stroke-width', (d) => {
   121→        if (showLinkStrength) {
   122→          const key = getEdgeKey(d.source as string, d.target as string);
   123→          const strengthInfo = linkStrengthMap.get(key);
   124→          if (strengthInfo) {
   125→            return strengthInfo.thickness;
   126→          }
   127→        }
   128→        return d.type === 'backlink' ? 2 : 1;
   129→      })
   130→      .attr('stroke-dasharray', (d) => {
   131→        if (showLinkStrength) {
   132→          const key = getEdgeKey(d.source as string, d.target as string);
   133→          const strengthInfo = linkStrengthMap.get(key);
   134→          if (strengthInfo?.isDashed) {
   135→            return '4,4';
   136→          }
   137→        }
   138→        return 'none';
   139→      })
   140→      .attr('marker-end', (d) => (d.type === 'backlink' ? 'url(#arrowhead)' : ''))
   141→      .attr('class', 'dark:stroke-border-dark');
   142→
   143→    // Create node groups
   144→    const node = g
   145→      .append('g')
   146→      .attr('class', 'nodes')
   147→      .selectAll('g')
   148→      .data(data.nodes)
   149→      .join('g')
   150→      .attr('cursor', 'pointer');
   151→
   152→    // Add drag behavior
   153→    const dragBehavior = d3
   154→      .drag<SVGGElement, any>()
   155→      .on('start', (event, d: any) => {
   156→        if (!event.active) simulation.alphaTarget(0.3).restart();
   157→        d.fx = d.x;
   158→        d.fy = d.y;
   159→      })
   160→      .on('drag', (event, d: any) => {
   161→        d.fx = event.x;
   162→        d.fy = event.y;
   163→      })
   164→      .on('end', (event, d: any) => {
   165→        if (!event.active) simulation.alphaTarget(0);
   166→        d.fx = null;
   167→        d.fy = null;
   168→      });
   169→
   170→    node.call(dragBehavior as any);
   171→
   172→    // Add circles to nodes
   173→    node
   174→      .append('circle')
   175→      .attr('r', (d) => {
   176→        // Get search highlight style
   177→        const highlightStyle = getSearchHighlightStyle(d.id, searchResult);
   178→
   179→        // Make focused node larger
   180→        if (focusNodeId && d.id === focusNodeId) {
   181→          return d.size * 1.5;
   182→        }
   183→
   184→        // Apply search scaling
   185→        return d.size * highlightStyle.scale;
   186→      })
   187→      .attr('fill', (d) => {
   188→        // Highlight focused node with gold color
   189→        if (focusNodeId && d.id === focusNodeId) {
   190→          return '#FFD700'; // Gold
   191→        }
   192→
   193→        // Orphan nodes get a distinct color
   194→        if (orphanIds.has(d.id)) {
   195→          return 'var(--accent-magenta)';
   196→        }
   197→
   198→        return d.color;
   199→      })
   200→      .attr('stroke', (d) => {
   201→        // Focused node gets accent border
   202→        if (focusNodeId && d.id === focusNodeId) {
   203→          return 'var(--accent-magenta)';
   204→        }
   205→
   206→        // Orphan nodes get warning-style border
   207→        if (orphanIds.has(d.id)) {
   208→          return '#f59e0b'; // Orange/amber
   209→        }
   210→
   211→        return 'var(--surface-light-base)';
   212→      })
   213→      .attr('stroke-width', (d) => {
   214→        // Get search highlight style
   215→        const highlightStyle = getSearchHighlightStyle(d.id, searchResult);
   216→
   217→        // Focused node gets thicker border
   218→        if (focusNodeId && d.id === focusNodeId) {
   219→          return 4;
   220→        }
   221→
   222→        // Orphan nodes get thicker border
   223→        if (orphanIds.has(d.id)) {
   224→          return 3;
   225→        }
   226→
   227→        return highlightStyle.strokeWidth;
   228→      })
   229→      .attr('opacity', (d) => {
   230→        // Get search highlight style
   231→        const highlightStyle = getSearchHighlightStyle(d.id, searchResult);
   232→        return highlightStyle.opacity;
   233→      })
   234→      .attr('class', 'dark:stroke-surface-dark-base transition-all duration-300');
   235→
   236→    // Add labels to nodes
   237→    node
   238→      .append('text')
   239→      .text((d) => d.label)
   240→      .attr('x', 0)
   241→      .attr('y', (d) => d.size + 15)
   242→      .attr('text-anchor', 'middle')
   243→      .attr('opacity', (d) => {
   244→        // Match label opacity to node opacity from search
   245→        const highlightStyle = getSearchHighlightStyle(d.id, searchResult);
   246→        return highlightStyle.opacity;
   247→      })
   248→      .attr('class', 'text-xs fill-text-light-primary dark:fill-text-dark-primary')
   249→      .attr('pointer-events', 'none');
   250→
   251→    // Add tooltips to nodes (P1: Show connections and tags)
   252→    node.append('title').text((d) => {
   253→      const parts: string[] = [d.label];
   254→
   255→      // Add connection count
   256→      if (d.connections !== undefined) {
   257→        parts.push(`${d.connections} connection${d.connections !== 1 ? 's' : ''}`);
   258→      }
   259→
   260→      // Add primary tag (for notes)
   261→      if (d.type === 'note' && d.metadata.tags && d.metadata.tags.length > 0) {
   262→        parts.push(`Tag: ${d.metadata.tags[0]}`);
   263→      }
   264→
   265→      // Add folder (for notes)
   266→      if (d.type === 'note' && d.metadata.folder) {
   267→        parts.push(`Folder: ${d.metadata.folder}`);
   268→      }
   269→
   270→      return parts.join('\n');
   271→    });
   272→
   273→    // Add click handler (single-click for focus)
   274→    node.on('click', (event, d) => {
   275→      event.stopPropagation();
   276→      if (onNodeClick) {
   277→        onNodeClick(d.id, d.type);
   278→      }
   279→    });
   280→
   281→    // Add double-click handler (navigate to note)
   282→    node.on('dblclick', (event, d) => {
   283→      event.stopPropagation();
   284→      if (onNodeDoubleClick) {
   285→        onNodeDoubleClick(d.id, d.type);
   286→      }
   287→    });
   288→
   289→    // Add hover effect
   290→    node.on('mouseenter', function () {
   291→      d3.select(this).select('circle').attr('stroke-width', 3);
   292→    });
   293→
   294→    node.on('mouseleave', function () {
   295→      d3.select(this).select('circle').attr('stroke-width', 2);
   296→    });
   297→
   298→    // Update positions on simulation tick
   299→    simulation.on('tick', () => {
   300→      link
   301→        .attr('x1', (d: any) => d.source.x ?? 0)
   302→        .attr('y1', (d: any) => d.source.y ?? 0)
   303→        .attr('x2', (d: any) => d.target.x ?? 0)
   304→        .attr('y2', (d: any) => d.target.y ?? 0);
   305→
   306→      node.attr('transform', (d: any) => {
   307→        const x = d.x ?? 0;
   308→        const y = d.y ?? 0;
   309→        return `translate(${x},${y})`;
   310→      });
   311→    });
   312→
   313→    // Stop simulating after it settles
   314→    simulation.on('end', () => {
   315→      setIsSimulating(false);
   316→    });
   317→
   318→    // Cleanup
   319→    return () => {
   320→      stopSimulation(simulation);
   321→    };
   322→  }, [data, width, height, onNodeClick, onNodeDoubleClick, focusNodeId, searchResult, showLinkStrength, orphanIds]);
   323→
   324→  return (
   325→    <div className="relative w-full h-full">
   326→      {isSimulating && (
   327→        <div className="absolute top-4 right-4 text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
   328→          Calculating layout...
   329→        </div>
   330→      )}
   331→      <svg
   332→        ref={svgRef}
   333→        width={width}
   334→        height={height}
   335→        className="border border-border-light dark:border-border-dark rounded-lg bg-surface-light-base dark:bg-surface-dark-base"
   336→      />
   337→    </div>
   338→  );
   339→}
