     1→/**
     2→ * Graph Data Processor
     3→ * Transforms notes, tasks, and their relationships into graph data for visualization
     4→ */
     5→
     6→import type { Note } from '../types/notes';
     7→
     8→export interface GraphNode {
     9→  id: string;
    10→  type: 'note' | 'tag';
    11→  label: string;
    12→  color: string; // Semantic color token
    13→  size: number; // Based on connection count
    14→  connections?: number; // P1: Connection count for tooltips
    15→  metadata: {
    16→    createdAt?: string;
    17→    folder?: string;
    18→    tags?: string[];
    19→  };
    20→}
    21→
    22→export interface GraphEdge {
    23→  source: string; // Node ID
    24→  target: string; // Node ID
    25→  type: 'backlink' | 'tag';
    26→  strength: number; // For force simulation
    27→}
    28→
    29→export interface GraphData {
    30→  nodes: GraphNode[];
    31→  edges: GraphEdge[];
    32→}
    33→
    34→export interface GraphFilters {
    35→  searchQuery?: string;
    36→  selectedTags?: string[];
    37→  selectedFolders?: string[];
    38→  hideOrphans?: boolean;
    39→  focusNodeId?: string;
    40→  focusDepth?: number; // 1-3 hops from focused node
    41→  colorBy?: 'folder' | 'tag' | 'none'; // P1: Color grouping
    42→  sizeByConnections?: boolean; // P1: Node sizing (default: true)
    43→}
    44→
    45→/**
    46→ * P1: Generate color palette for graph node groups
    47→ * Returns HSL colors with good visual separation
    48→ */
    49→function generateColorPalette(count: number): string[] {
    50→  const colors: string[] = [];
    51→  const saturation = 70;
    52→  const lightness = 55;
    53→
    54→  for (let i = 0; i < count; i++) {
    55→    // Distribute hues evenly around color wheel
    56→    const hue = (i * 360) / count;
    57→    colors.push(`hsl(${hue}, ${saturation}%, ${lightness}%)`);
    58→  }
    59→
    60→  return colors;
    61→}
    62→
    63→/**
    64→ * P1: Assign colors to nodes based on grouping strategy
    65→ */
    66→function assignNodeColors(
    67→  nodes: GraphNode[],
    68→  colorBy: 'folder' | 'tag' | 'none'
    69→): Map<string, string> {
    70→  const colorMap = new Map<string, string>();
    71→
    72→  if (colorBy === 'none') {
    73→    // Use default semantic colors
    74→    return colorMap;
    75→  }
    76→
    77→  if (colorBy === 'folder') {
    78→    // Group by folder
    79→    const folders = new Set<string>();
    80→    nodes.forEach((node) => {
    81→      if (node.type === 'note') {
    82→        const folder = node.metadata.folder || 'root';
    83→        folders.add(folder);
    84→      }
    85→    });
    86→
    87→    const folderArray = Array.from(folders).sort();
    88→    const palette = generateColorPalette(folderArray.length);
    89→
    90→    folderArray.forEach((folder, index) => {
    91→      colorMap.set(folder, palette[index]);
    92→    });
    93→
    94→    return colorMap;
    95→  }
    96→
    97→  if (colorBy === 'tag') {
    98→    // Group by primary tag (first tag if multiple)
    99→    const tags = new Set<string>();
   100→    nodes.forEach((node) => {
   101→      if (node.type === 'note' && node.metadata.tags && node.metadata.tags.length > 0) {
   102→        tags.add(node.metadata.tags[0]);
   103→      }
   104→    });
   105→
   106→    const tagArray = Array.from(tags).sort();
   107→    const palette = generateColorPalette(tagArray.length);
   108→
   109→    tagArray.forEach((tag, index) => {
   110→      colorMap.set(tag, palette[index]);
   111→    });
   112→
   113→    return colorMap;
   114→  }
   115→
   116→  return colorMap;
   117→}
   118→
   119→/**
   120→ * Get all nodes within N degrees of separation from a target node
   121→ * Uses breadth-first search to traverse the graph
   122→ */
   123→function getNodesWithinDepth(
   124→  nodeId: string,
   125→  depth: number,
   126→  edges: GraphEdge[]
   127→): Set<string> {
   128→  const visited = new Set<string>([nodeId]);
   129→  let currentLevel = [nodeId];
   130→
   131→  for (let d = 0; d < depth; d++) {
   132→    const nextLevel: string[] = [];
   133→
   134→    for (const current of currentLevel) {
   135→      // Find all directly connected nodes
   136→      const connected = edges
   137→        .filter(e => e.source === current || e.target === current)
   138→        .map(e => e.source === current ? e.target : e.source);
   139→
   140→      for (const neighbor of connected) {
   141→        if (!visited.has(neighbor)) {
   142→          visited.add(neighbor);
   143→          nextLevel.push(neighbor);
   144→        }
   145→      }
   146→    }
   147→
   148→    currentLevel = nextLevel;
   149→  }
   150→
   151→  return visited;
   152→}
   153→
   154→/**
   155→ * Build graph data from notes
   156→ */
   157→export function buildGraphData(
   158→  notes: Record<string, Note>,
   159→  filters: GraphFilters = {}
   160→): GraphData {
   161→  const nodes: GraphNode[] = [];
   162→  const edges: GraphEdge[] = [];
   163→  const nodeMap = new Map<string, GraphNode>();
   164→  const tagNodeMap = new Map<string, GraphNode>();
   165→
   166→  // Get all notes as array
   167→  const notesArray = Object.values(notes);
   168→
   169→  // Filter notes based on search/folder filters
   170→  let filteredNotes = notesArray;
   171→
   172→  if (filters.searchQuery) {
   173→    const query = filters.searchQuery.toLowerCase();
   174→    filteredNotes = filteredNotes.filter(
   175→      (note) =>
   176→        note.title.toLowerCase().includes(query) ||
   177→        note.content.toLowerCase().includes(query)
   178→    );
   179→  }
   180→
   181→  if (filters.selectedFolders && filters.selectedFolders.length > 0) {
   182→    filteredNotes = filteredNotes.filter((note) =>
   183→      filters.selectedFolders!.includes(note.folderId || 'root')
   184→    );
   185→  }
   186→
   187→  // Create note nodes
   188→  filteredNotes.forEach((note) => {
   189→    const node: GraphNode = {
   190→      id: note.id,
   191→      type: 'note',
   192→      label: note.title || 'Untitled',
   193→      color: 'var(--accent-cyan)', // Semantic token for notes
   194→      size: 10, // Base size, will be updated based on connections
   195→      metadata: {
   196→        createdAt: note.createdAt.toString(),
   197→        folder: note.folderId || undefined,
   198→        tags: note.tags || [],
   199→      },
   200→    };
   201→    nodes.push(node);
   202→    nodeMap.set(note.id, node);
   203→  });
   204→
   205→  // Create tag nodes and tag edges
   206→  const allTags = new Set<string>();
   207→  filteredNotes.forEach((note) => {
   208→    if (note.tags && note.tags.length > 0) {
   209→      note.tags.forEach((tag) => allTags.add(tag));
   210→    }
   211→  });
   212→
   213→  // Filter by selected tags if provided
   214→  let tagsToInclude = Array.from(allTags);
   215→  if (filters.selectedTags && filters.selectedTags.length > 0) {
   216→    tagsToInclude = tagsToInclude.filter((tag) =>
   217→      filters.selectedTags!.includes(tag)
   218→    );
   219→  }
   220→
   221→  tagsToInclude.forEach((tag) => {
   222→    const tagNode: GraphNode = {
   223→      id: `tag:${tag}`,
   224→      type: 'tag',
   225→      label: tag,
   226→      color: 'var(--accent-magenta)', // Semantic token for tags
   227→      size: 8, // Tags slightly smaller
   228→      metadata: {
   229→        tags: [tag],
   230→      },
   231→    };
   232→    nodes.push(tagNode);
   233→    tagNodeMap.set(tag, tagNode);
   234→  });
   235→
   236→  // Create tag edges (note → tag)
   237→  filteredNotes.forEach((note) => {
   238→    if (note.tags && note.tags.length > 0) {
   239→      note.tags.forEach((tag) => {
   240→        if (tagNodeMap.has(tag)) {
   241→          edges.push({
   242→            source: note.id,
   243→            target: `tag:${tag}`,
   244→            type: 'tag',
   245→            strength: 0.5, // Weaker than backlinks
   246→          });
   247→        }
   248→      });
   249→    }
   250→  });
   251→
   252→  // Create edges from linkedNotes (notes that this note links TO)
   253→  filteredNotes.forEach((note) => {
   254→    if (note.linkedNotes && note.linkedNotes.length > 0) {
   255→      note.linkedNotes.forEach((linkedNoteId: string) => {
   256→        // Only create edge if target note exists in filtered set
   257→        if (nodeMap.has(linkedNoteId)) {
   258→          edges.push({
   259→            source: note.id,
   260→            target: linkedNoteId,
   261→            type: 'backlink',
   262→            strength: 1.0, // Stronger connection
   263→          });
   264→        }
   265→      });
   266→    }
   267→  });
   268→
   269→  // P1: Calculate connection counts for all nodes (used for sizing and tooltips)
   270→  const connectionCounts = new Map<string, number>();
   271→  edges.forEach((edge) => {
   272→    connectionCounts.set(edge.source, (connectionCounts.get(edge.source) || 0) + 1);
   273→    connectionCounts.set(edge.target, (connectionCounts.get(edge.target) || 0) + 1);
   274→  });
   275→
   276→  // Store connection count in metadata for tooltips
   277→  nodes.forEach((node) => {
   278→    node.connections = connectionCounts.get(node.id) || 0;
   279→  });
   280→
   281→  // Update node sizes based on connection count (if enabled)
   282→  if (filters.sizeByConnections !== false) { // Default to true if not specified
   283→    nodes.forEach((node) => {
   284→      const count = node.connections || 0;
   285→      // Size scales with connections: 10-30 for notes, 8-20 for tags
   286→      const baseSize = node.type === 'note' ? 10 : 8;
   287→      const maxSize = node.type === 'note' ? 30 : 20;
   288→      node.size = Math.min(baseSize + count * 2, maxSize);
   289→    });
   290→  }
   291→  // If sizeByConnections is false, keep default sizes (already set at node creation)
   292→
   293→  // P1: Apply color grouping if specified
   294→  if (filters.colorBy && filters.colorBy !== 'none') {
   295→    const colorMap = assignNodeColors(nodes, filters.colorBy);
   296→
   297→    nodes.forEach((node) => {
   298→      if (node.type === 'note') {
   299→        let groupKey: string | undefined;
   300→
   301→        if (filters.colorBy === 'folder') {
   302→          groupKey = node.metadata.folder || 'root';
   303→        } else if (filters.colorBy === 'tag' && node.metadata.tags && node.metadata.tags.length > 0) {
   304→          groupKey = node.metadata.tags[0];
   305→        }
   306→
   307→        if (groupKey && colorMap.has(groupKey)) {
   308→          node.color = colorMap.get(groupKey)!;
   309→        }
   310→      }
   311→      // Tag nodes keep their default magenta color
   312→    });
   313→  }
   314→
   315→  // Filter orphan nodes if requested
   316→  let finalNodes = nodes;
   317→  let finalEdges = edges;
   318→
   319→  if (filters.hideOrphans) {
   320→    const connectedNodeIds = new Set<string>();
   321→    edges.forEach((edge) => {
   322→      connectedNodeIds.add(edge.source);
   323→      connectedNodeIds.add(edge.target);
   324→    });
   325→    finalNodes = nodes.filter((node) => connectedNodeIds.has(node.id));
   326→  }
   327→
   328→  // Focus mode: show only nodes within N hops of focused node
   329→  if (filters.focusNodeId && filters.focusDepth) {
   330→    const focusedNodeIds = getNodesWithinDepth(
   331→      filters.focusNodeId,
   332→      filters.focusDepth,
   333→      edges
   334→    );
   335→
   336→    finalNodes = finalNodes.filter(n => focusedNodeIds.has(n.id));
   337→    finalEdges = edges.filter(e =>
   338→      focusedNodeIds.has(e.source) && focusedNodeIds.has(e.target)
   339→    );
   340→  }
   341→
   342→  return {
   343→    nodes: finalNodes,
   344→    edges: finalEdges,
   345→  };
   346→}
   347→
   348→/**
   349→ * Get unique folders from notes
   350→ */
   351→export function getUniqueFolders(notes: Record<string, Note>): string[] {
   352→  const folders = new Set<string>();
   353→  Object.values(notes).forEach((note) => {
   354→    if (note.folderId) {
   355→      folders.add(note.folderId);
   356→    } else {
   357→      folders.add('root');
   358→    }
   359→  });
   360→  return Array.from(folders);
   361→}
   362→
   363→/**
   364→ * Get unique tags from notes
   365→ */
   366→export function getUniqueTags(notes: Record<string, Note>): string[] {
   367→  const tags = new Set<string>();
   368→  Object.values(notes).forEach((note) => {
   369→    if (note.tags && note.tags.length > 0) {
