     1→/**
     2→ * Graph Orphan Detection
     3→ * Identifies isolated nodes and suggests connections
     4→ */
     5→
     6→import type { GraphNode, GraphEdge } from './graphDataProcessor';
     7→import type { OrphanNode, OrphanSuggestion } from '../types/graph';
     8→import type { Note } from '../types/notes';
     9→
    10→/**
    11→ * Detect orphan nodes (nodes with no connections)
    12→ */
    13→export function detectOrphans(
    14→  nodes: GraphNode[],
    15→  edges: GraphEdge[]
    16→): Set<string> {
    17→  const connectedNodeIds = new Set<string>();
    18→
    19→  // Mark all nodes that have at least one connection
    20→  edges.forEach((edge) => {
    21→    connectedNodeIds.add(edge.source);
    22→    connectedNodeIds.add(edge.target);
    23→  });
    24→
    25→  // Orphans are nodes not in the connected set
    26→  const orphanIds = new Set<string>();
    27→  nodes.forEach((node) => {
    28→    // Only notes can be orphans (tag nodes are expected to have no connections)
    29→    if (node.type === 'note' && !connectedNodeIds.has(node.id)) {
    30→      orphanIds.add(node.id);
    31→    }
    32→  });
    33→
    34→  return orphanIds;
    35→}
    36→
    37→/**
    38→ * Calculate string similarity using Levenshtein distance
    39→ * Returns score 0-1 (1 = identical)
    40→ */
    41→function calculateSimilarity(str1: string, str2: string): number {
    42→  const s1 = str1.toLowerCase();
    43→  const s2 = str2.toLowerCase();
    44→
    45→  const len1 = s1.length;
    46→  const len2 = s2.length;
    47→
    48→  if (len1 === 0) return len2 === 0 ? 1 : 0;
    49→  if (len2 === 0) return 0;
    50→
    51→  // Create distance matrix
    52→  const matrix: number[][] = [];
    53→  for (let i = 0; i <= len2; i++) {
    54→    matrix[i] = [i];
    55→  }
    56→  for (let j = 0; j <= len1; j++) {
    57→    matrix[0][j] = j;
    58→  }
    59→
    60→  // Fill matrix
    61→  for (let i = 1; i <= len2; i++) {
    62→    for (let j = 1; j <= len1; j++) {
    63→      if (s2.charAt(i - 1) === s1.charAt(j - 1)) {
    64→        matrix[i][j] = matrix[i - 1][j - 1];
    65→      } else {
    66→        matrix[i][j] = Math.min(
    67→          matrix[i - 1][j - 1] + 1, // substitution
    68→          matrix[i][j - 1] + 1, // insertion
    69→          matrix[i - 1][j] + 1 // deletion
    70→        );
    71→      }
    72→    }
    73→  }
    74→
    75→  const distance = matrix[len2][len1];
    76→  const maxLen = Math.max(len1, len2);
    77→  return 1 - distance / maxLen;
    78→}
    79→
    80→/**
    81→ * Generate connection suggestions for an orphan node
    82→ */
    83→export function generateConnectionSuggestions(
    84→  orphanId: string,
    85→  orphanNode: GraphNode,
    86→  allNodes: GraphNode[],
    87→  notes: Record<string, Note>
    88→): OrphanSuggestion[] {
    89→  const suggestions: OrphanSuggestion[] = [];
    90→  const orphanNote = notes[orphanId];
    91→
    92→  if (!orphanNote) return suggestions;
    93→
    94→  // Get other note nodes (exclude the orphan itself and tag nodes)
    95→  const otherNotes = allNodes.filter(
    96→    (node) => node.type === 'note' && node.id !== orphanId
    97→  );
    98→
    99→  // Suggestion 1: Similar title
   100→  otherNotes.forEach((node) => {
   101→    const similarity = calculateSimilarity(orphanNode.label, node.label);
   102→    if (similarity > 0.5) {
   103→      // 50% similarity threshold
   104→      suggestions.push({
   105→        orphanId,
   106→        suggestedNoteId: node.id,
   107→        reason: 'similar-title',
   108→        confidence: similarity,
   109→      });
   110→    }
   111→  });
   112→
   113→  // Suggestion 2: Same folder
   114→  if (orphanNote.folderId) {
   115→    otherNotes.forEach((node) => {
   116→      const noteData = notes[node.id];
   117→      if (noteData && noteData.folderId === orphanNote.folderId) {
   118→        suggestions.push({
   119→          orphanId,
   120→          suggestedNoteId: node.id,
   121→          reason: 'same-folder',
   122→          confidence: 0.7,
   123→        });
   124→      }
   125→    });
   126→  }
   127→
   128→  // Suggestion 3: Recently edited (within 7 days)
   129→  const orphanDate = new Date(orphanNote.createdAt);
   130→  const sevenDaysAgo = new Date(orphanDate.getTime() - 7 * 24 * 60 * 60 * 1000);
   131→
   132→  otherNotes.forEach((node) => {
   133→    const noteData = notes[node.id];
   134→    if (noteData) {
   135→      const noteDate = new Date(noteData.updatedAt || noteData.createdAt);
   136→      if (noteDate >= sevenDaysAgo && noteDate <= orphanDate) {
   137→        suggestions.push({
   138→          orphanId,
   139→          suggestedNoteId: node.id,
   140→          reason: 'recent-edit',
   141→          confidence: 0.6,
   142→        });
   143→      }
   144→    }
   145→  });
   146→
   147→  // Suggestion 4: Similar content (basic word matching)
   148→  const orphanWords = new Set(
   149→    orphanNote.content
   150→      .toLowerCase()
   151→      .split(/\s+/)
   152→      .filter((w) => w.length > 4) // Only words longer than 4 chars
   153→  );
   154→
   155→  if (orphanWords.size > 0) {
   156→    otherNotes.forEach((node) => {
   157→      const noteData = notes[node.id];
   158→      if (noteData && noteData.content) {
   159→        const noteWords = noteData.content
   160→          .toLowerCase()
   161→          .split(/\s+/)
   162→          .filter((w) => w.length > 4);
   163→
   164→        // Count common words
   165→        const commonWords = noteWords.filter((w) => orphanWords.has(w));
   166→        const similarity = commonWords.length / Math.max(orphanWords.size, 1);
   167→
   168→        if (similarity > 0.2) {
   169→          // 20% common words
   170→          suggestions.push({
   171→            orphanId,
   172→            suggestedNoteId: node.id,
   173→            reason: 'similar-content',
   174→            confidence: Math.min(similarity * 2, 0.9), // Scale up but cap at 0.9
   175→          });
   176→        }
   177→      }
   178→    });
   179→  }
   180→
   181→  // Suggestion 5: Suggest adding common tags
   182→  // Find most common tags in the folder
   183→  if (orphanNote.folderId) {
   184→    const tagFrequency = new Map<string, number>();
   185→
   186→    otherNotes.forEach((node) => {
   187→      const noteData = notes[node.id];
   188→      if (noteData && noteData.folderId === orphanNote.folderId && noteData.tags) {
   189→        noteData.tags.forEach((tag) => {
   190→          tagFrequency.set(tag, (tagFrequency.get(tag) || 0) + 1);
   191→        });
   192→      }
   193→    });
   194→
   195→    // Get top 3 tags
   196→    const topTags = Array.from(tagFrequency.entries())
   197→      .sort((a, b) => b[1] - a[1])
   198→      .slice(0, 3);
   199→
   200→    topTags.forEach(([tag]) => {
   201→      // Find a note with this tag to suggest
   202→      const noteWithTag = otherNotes.find((node) => {
   203→        const noteData = notes[node.id];
   204→        return noteData?.tags?.includes(tag);
   205→      });
   206→
   207→      if (noteWithTag) {
   208→        suggestions.push({
   209→          orphanId,
   210→          suggestedNoteId: noteWithTag.id,
   211→          reason: 'same-folder',
   212→          confidence: 0.5,
   213→          suggestedTag: tag,
   214→        });
   215→      }
   216→    });
   217→  }
   218→
   219→  // Sort by confidence (highest first) and deduplicate
   220→  const uniqueSuggestions = new Map<string, OrphanSuggestion>();
   221→  suggestions.forEach((suggestion) => {
   222→    const existing = uniqueSuggestions.get(suggestion.suggestedNoteId);
   223→    if (!existing || existing.confidence < suggestion.confidence) {
   224→      uniqueSuggestions.set(suggestion.suggestedNoteId, suggestion);
   225→    }
   226→  });
   227→
   228→  return Array.from(uniqueSuggestions.values())
   229→    .sort((a, b) => b.confidence - a.confidence)
   230→    .slice(0, 5); // Top 5 suggestions
   231→}
   232→
   233→/**
   234→ * Get all orphan nodes with suggestions
   235→ */
   236→export function getOrphansWithSuggestions(
   237→  nodes: GraphNode[],
   238→  edges: GraphEdge[],
   239→  notes: Record<string, Note>
   240→): OrphanNode[] {
   241→  const orphanIds = detectOrphans(nodes, edges);
   242→  const orphanNodes: OrphanNode[] = [];
   243→
   244→  orphanIds.forEach((orphanId) => {
