                  }`}
                >
                  {type === 'both'
                    ? 'All'
                    : type === 'note'
                    ? 'Notes only'
                    : 'Tags only'}
                </button>
              ))}
            </div>
          </div>

          {/* Active filter chips */}
          {hasActiveFilters && (
            <div className="flex flex-wrap gap-2 pt-2 border-t border-border-light dark:border-border-dark">
              {filters.query && (
                <div className="flex items-center gap-1 px-2 py-1 text-xs rounded-full bg-accent-magenta/10 text-accent-magenta">
                  <span>Query: "{filters.query}"</span>
                  <button
                    onClick={() => {
                      setLocalQuery('');
                      onFiltersChange({ ...filters, query: undefined });
                    }}
                    className="hover:bg-accent-magenta/20 rounded-full p-0.5"
                  >
                    <X className="w-3 h-3" />
                  </button>
                </div>
              )}
              {filters.tags?.map((tag) => (
                <div
                  key={tag}
                  className="flex items-center gap-1 px-2 py-1 text-xs rounded-full bg-accent-cyan/10 text-accent-cyan"
                >
                  <span>Tag: {tag}</span>
                  <button
                    onClick={() => {
                      const newTags = filters.tags!.filter((t) => t !== tag);
                      onFiltersChange({
                        ...filters,
                        tags: newTags.length > 0 ? newTags : undefined,
                      });
                    }}
                    className="hover:bg-accent-cyan/20 rounded-full p-0.5"
                  >
                    <X className="w-3 h-3" />
                  </button>
                </div>
              ))}
              {filters.nodeType && filters.nodeType !== 'both' && (
                <div className="flex items-center gap-1 px-2 py-1 text-xs rounded-full bg-accent-purple/10 text-accent-purple">
                  <span>
                    Type: {filters.nodeType === 'note' ? 'Notes' : 'Tags'}
                  </span>
                  <button
                    onClick={() =>
                      onFiltersChange({ ...filters, nodeType: 'both' })
                    }
                    className="hover:bg-accent-purple/20 rounded-full p-0.5"
                  >
                    <X className="w-3 h-3" />
                  </button>
                </div>
              )}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

/**
 * Orphan Panel Component
 * Sidebar panel showing orphan nodes with connection suggestions
 */

import { useState } from 'react';
import { AlertCircle, Link as LinkIcon, X, Tag, ChevronDown, ChevronRight } from 'lucide-react';
import type { OrphanNode } from '../../types/graph';

interface OrphanPanelProps {
  /** List of orphan nodes with suggestions */
  orphans: OrphanNode[];
  /** Callback when user wants to focus on an orphan */
  onFocusOrphan: (nodeId: string) => void;
  /** Callback when user wants to create a link */
  onCreateLink: (orphanId: string, targetId: string) => void;
  /** Callback when user wants to add a tag */
  onAddTag: (orphanId: string, tag: string) => void;
  /** Callback to close panel */
  onClose: () => void;
}

export function OrphanPanel({
  orphans,
  onFocusOrphan,
  onCreateLink,
  onAddTag,
  onClose,
}: OrphanPanelProps) {
  const [expandedOrphanId, setExpandedOrphanId] = useState<string | null>(null);

  const toggleExpanded = (nodeId: string) => {
    setExpandedOrphanId(expandedOrphanId === nodeId ? null : nodeId);
  };

  const getReasonLabel = (
    reason: 'similar-title' | 'same-folder' | 'recent-edit' | 'similar-content'
  ): string => {
    switch (reason) {
      case 'similar-title':
        return 'Similar title';
      case 'same-folder':
        return 'Same folder';
      case 'recent-edit':
        return 'Edited recently';
      case 'similar-content':
        return 'Similar content';
    }
  };

  const getReasonColor = (
    reason: 'similar-title' | 'same-folder' | 'recent-edit' | 'similar-content'
  ): string => {
    switch (reason) {
      case 'similar-title':
        return 'text-accent-magenta';
      case 'same-folder':
        return 'text-accent-cyan';
      case 'recent-edit':
        return 'text-accent-purple';
      case 'similar-content':
        return 'text-yellow-500';
    }
  };

  if (orphans.length === 0) {
    return (
      <div className="flex flex-col h-full bg-surface-light-base dark:bg-surface-dark-base border-l border-border-light dark:border-border-dark">
        <div className="flex items-center justify-between p-4 border-b border-border-light dark:border-border-dark">
          <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
            Orphan Nodes
          </h3>
          <button
            onClick={onClose}
            className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded"
            aria-label="Close orphan panel"
          >
            <X className="w-4 h-4 text-text-light-tertiary dark:text-text-dark-tertiary" />
          </button>
        </div>
        <div className="flex-1 flex items-center justify-center p-6">
          <div className="text-center">
            <AlertCircle className="w-12 h-12 mx-auto mb-3 text-accent-cyan opacity-50" />
            <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
              No orphan nodes found
            </p>
            <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1">
              All notes are connected!
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-surface-light-base dark:bg-surface-dark-base border-l border-border-light dark:border-border-dark w-80">
      {/* Header */}
      <div className="flex items-center justify-between p-4 border-b border-border-light dark:border-border-dark">
        <div className="flex items-center gap-2">
          <AlertCircle className="w-4 h-4 text-accent-magenta" />
          <h3 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
            Orphan Nodes
          </h3>
          <span className="px-2 py-0.5 text-xs rounded-full bg-accent-magenta/10 text-accent-magenta">
            {orphans.length}
          </span>
        </div>
        <button
          onClick={onClose}
          className="p-1 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors"
          aria-label="Close orphan panel"
        >
          <X className="w-4 h-4 text-text-light-tertiary dark:text-text-dark-tertiary" />
        </button>
      </div>

      {/* Orphan list */}
      <div className="flex-1 overflow-y-auto">
        {orphans.map((orphan) => {
          const isExpanded = expandedOrphanId === orphan.nodeId;
          const hasSuggestions = orphan.suggestions.length > 0;

          return (
            <div
              key={orphan.nodeId}
              className="border-b border-border-light dark:border-border-dark last:border-b-0"
            >
              {/* Orphan header */}
              <div className="p-3 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors">
                <div className="flex items-start gap-2">
                  {hasSuggestions && (
                    <button
                      onClick={() => toggleExpanded(orphan.nodeId)}
                      className="mt-0.5 text-text-light-tertiary dark:text-text-dark-tertiary hover:text-text-light-primary dark:hover:text-text-dark-primary"
                      aria-label={isExpanded ? 'Collapse' : 'Expand'}
                    >
                      {isExpanded ? (
                        <ChevronDown className="w-4 h-4" />
                      ) : (
                        <ChevronRight className="w-4 h-4" />
                      )}
                    </button>
                  )}
                  <div className="flex-1 min-w-0">
                    <button
                      onClick={() => onFocusOrphan(orphan.nodeId)}
                      className="text-left w-full group"
                    >
                      <h4 className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary truncate group-hover:text-accent-cyan transition-colors">
                        {orphan.title}
                      </h4>
                    </button>
                    {hasSuggestions && (
                      <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-0.5">
                        {orphan.suggestions.length} suggestion
                        {orphan.suggestions.length !== 1 ? 's' : ''}
                      </p>
                    )}
                    {!hasSuggestions && (
                      <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-0.5">
                        No suggestions available
                      </p>
                    )}
                  </div>
                </div>
              </div>

              {/* Suggestions (expanded) */}
              {isExpanded && hasSuggestions && (
                <div className="px-3 pb-3 pl-9 space-y-2">
                  {orphan.suggestions.map((suggestion, idx) => (
                    <div
                      key={`${suggestion.suggestedNoteId}-${idx}`}
                      className="p-2 rounded-lg bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark"
                    >
                      <div className="flex items-start gap-2 mb-2">
                        <div
                          className={`text-xs font-medium ${getReasonColor(
                            suggestion.reason
                          )}`}
                        >
                          {getReasonLabel(suggestion.reason)}
                        </div>
                        <div className="ml-auto text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
                          {Math.round(suggestion.confidence * 100)}%
                        </div>
                      </div>

                      <div className="flex items-center gap-2">
                        {suggestion.suggestedTag ? (
                          <button
                            onClick={() =>
                              onAddTag(orphan.nodeId, suggestion.suggestedTag!)
                            }
                            className="flex items-center gap-1.5 px-2 py-1 text-xs rounded bg-accent-magenta/10 text-accent-magenta hover:bg-accent-magenta/20 transition-colors"
                          >
                            <Tag className="w-3 h-3" />
                            <span>Add tag: {suggestion.suggestedTag}</span>
                          </button>
                        ) : (
                          <button
                            onClick={() =>
                              onCreateLink(
                                orphan.nodeId,
                                suggestion.suggestedNoteId
                              )
                            }
                            className="flex items-center gap-1.5 px-2 py-1 text-xs rounded bg-accent-cyan/10 text-accent-cyan hover:bg-accent-cyan/20 transition-colors"
                          >
                            <LinkIcon className="w-3 h-3" />
                            <span>Create link</span>
                          </button>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Footer */}
      <div className="p-3 border-t border-border-light dark:border-border-dark bg-surface-light-elevated dark:bg-surface-dark-elevated">
        <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
          Orphan nodes have no connections. Click suggestions to add links or tags.
        </p>
      </div>
    </div>
  );
}

# Prompt 025: Graph View Enhancements - Link Strength, Search, Orphans (P2)

## Objective
Add visual link strength indicators, search/highlight functionality, and orphan note toggle to complete professional graph visualization parity with Obsidian/Logseq.

## Context
- **Feature:** Notes & Knowledge Management (P2 - Graph View enhancements)
- **Current State:** D3 force-directed graph with focus mode, node sizing, color grouping
- **Gaps:**
  1. No visual indication of link strength (number of connections)
  2. No search functionality to find/highlight nodes
  3. No toggle to show/hide orphan (unlinked) notes
- **Priority:** P2 - Visual analytics improvements, not critical for core navigation

## Requirements

### Part 1: Link Strength Visualization

#### 1.1 Calculate Link Strength
**Purpose:** Thicker edges for notes with more connections

**Implementation:**
```typescript
// In src/utils/graphDataProcessor.ts
interface GraphEdge {
  source: string;
  target: string;
  type: 'backlink' | 'tag';
  strength: number; // NEW: 1-10 scale
}

export function calculateLinkStrength(
  sourceId: string,
  targetId: string,
  notes: Note[]
): number {
  // Count bidirectional connections
  const sourceNote = notes.find(n => n.id === sourceId);
  const targetNote = notes.find(n => n.id === targetId);

  let strength = 1; // Base strength

  // +1 for each shared tag
  const sharedTags = sourceNote?.tags.filter(t => targetNote?.tags.includes(t)) || [];
  strength += sharedTags.length * 0.5;

  // +2 if bidirectional link (both notes link to each other)
  const sourceLinksToTarget = sourceNote?.linkedNotes.includes(targetId);
  const targetLinksToSource = targetNote?.linkedNotes.includes(sourceId);
  if (sourceLinksToTarget && targetLinksToSource) {
    strength += 2;
  }

  // Cap at 10
  return Math.min(strength, 10);
}
```

#### 1.2 Render Strength with Stroke Width
**Purpose:** Visual encoding of relationship strength

**Implementation:**
```typescript
// In src/components/Graph/GraphCanvas.tsx
svg.selectAll('.link')
  .data(edges)
  .join('line')
  .attr('class', 'link')
  .attr('stroke', d => d.type === 'backlink' ? '#0891b2' : '#64748b')
  .attr('stroke-width', d => {
    // Map strength (1-10) to stroke width (1-5px)
    return 1 + (d.strength - 1) * 0.4;
  })
  .attr('stroke-opacity', d => {
    // Stronger links = more opaque
    return 0.3 + (d.strength / 10) * 0.4;
  })
  .attr('marker-end', 'url(#arrowhead)');
```

### Part 2: Search & Highlight

#### 2.1 Search Bar Component
**Purpose:** Find nodes by note title

**Implementation:**
```typescript
// In src/pages/GraphView.tsx
const [searchQuery, setSearchQuery] = useState('');
const [highlightedNodes, setHighlightedNodes] = useState<string[]>([]);

const handleSearch = (query: string) => {
  setSearchQuery(query);

  if (!query.trim()) {
    setHighlightedNodes([]);
    return;
  }

  // Fuzzy search on note titles
  const matches = notes.filter(note =>
    note.title.toLowerCase().includes(query.toLowerCase())
  ).map(n => n.id);

  setHighlightedNodes(matches);
};

// In JSX:
<div className="mb-4">
  <input
    type="text"
    value={searchQuery}
    onChange={(e) => handleSearch(e.target.value)}
    placeholder="Search nodes..."
    className="w-full px-3 py-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg"
  />
  {highlightedNodes.length > 0 && (
    <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary mt-1">
      Found {highlightedNodes.length} nodes
    </p>
  )}
</div>
```

#### 2.2 Highlight Nodes in Graph
**Purpose:** Visual emphasis on search results

**Implementation:**
```typescript
// In src/components/Graph/GraphCanvas.tsx
svg.selectAll('.node')
  .data(nodes)
  .join('circle')
  .attr('class', 'node')
  .attr('r', d => {
    // Highlighted nodes = larger
    return highlightedNodeIds.includes(d.id) ? nodeSize * 1.5 : nodeSize;
  })
  .attr('fill', d => {
    // Highlighted nodes = gold
    if (highlightedNodeIds.includes(d.id)) {
      return '#facc15'; // yellow-400
    }
    return getNodeColor(d);
  })
  .attr('stroke', d => {
    // Highlighted nodes = thick border
    return highlightedNodeIds.includes(d.id) ? '#eab308' : '#64748b';
  })
  .attr('stroke-width', d => {
    return highlightedNodeIds.includes(d.id) ? 3 : 1.5;
  });

// Dim non-highlighted nodes when search active
if (highlightedNodeIds.length > 0) {
  svg.selectAll('.node')
    .filter(d => !highlightedNodeIds.includes(d.id))
    .attr('opacity', 0.3);

  svg.selectAll('.link')
    .filter(d => {
      // Dim edges not connected to highlighted nodes
      return !highlightedNodeIds.includes(d.source.id) &&
             !highlightedNodeIds.includes(d.target.id);
    })
    .attr('opacity', 0.1);
}
```

#### 2.3 Click Result to Center
**Purpose:** Navigate to search result in graph

**Implementation:**
```typescript
// Add function to center and zoom to node
const centerOnNode = (nodeId: string) => {
  const node = nodes.find(n => n.id === nodeId);
  if (!node) return;

  // Zoom and pan to center on node
  const svg = d3.select(svgRef.current);
  const transform = d3.zoomIdentity
    .translate(width / 2, height / 2)
    .scale(2)
    .translate(-node.x, -node.y);

  svg.transition()
    .duration(750)
    .call(zoom.transform, transform);
};

// Keyboard shortcut: Enter on first result
useEffect(() => {
  const handleKeyDown = (e: KeyboardEvent) => {
    if (e.key === 'Enter' && highlightedNodes.length > 0) {
      centerOnNode(highlightedNodes[0]);
    }
  };

  window.addEventListener('keydown', handleKeyDown);
  return () => window.removeEventListener('keydown', handleKeyDown);
}, [highlightedNodes]);
```

### Part 3: Orphan Notes Toggle

#### 3.1 Show/Hide Orphans Checkbox
**Purpose:** Filter unlinked notes from graph

**Implementation:**
```typescript
// In src/pages/GraphView.tsx
const [showOrphans, setShowOrphans] = useState(true);

// In JSX (next to other controls):
<label className="flex items-center gap-2">
  <input
    type="checkbox"
    checked={showOrphans}
    onChange={(e) => setShowOrphans(e.target.checked)}
    className="rounded border-border-light dark:border-border-dark"
  />
  <span className="text-sm">Show orphan notes</span>
</label>

