```

#### 3.2 Filter Orphans from Graph Data
**Purpose:** Remove isolated nodes from visualization

**Implementation:**
```typescript
// In src/utils/graphDataProcessor.ts
export function filterOrphans(
  nodes: GraphNode[],
  edges: GraphEdge[]
): { nodes: GraphNode[]; edges: GraphEdge[] } {
  // Find nodes with no edges
  const connectedNodeIds = new Set<string>();
  edges.forEach(edge => {
    connectedNodeIds.add(edge.source);
    connectedNodeIds.add(edge.target);
  });

  const filteredNodes = nodes.filter(node =>
    connectedNodeIds.has(node.id) || node.type === 'tag'
  );

  return { nodes: filteredNodes, edges };
}

// In src/pages/GraphView.tsx
const graphData = useMemo(() => {
  let data = processGraphData(notes, tags);

  if (!showOrphans) {
    data = filterOrphans(data.nodes, data.edges);
  }

  return data;
}, [notes, tags, showOrphans]);
```

#### 3.3 Orphan Count Badge
**Purpose:** Show how many orphans are hidden

**Implementation:**
```typescript
const orphanCount = useMemo(() => {
  const connectedNodeIds = new Set<string>();
  edges.forEach(edge => {
    connectedNodeIds.add(edge.source);
    connectedNodeIds.add(edge.target);
  });

  return notes.filter(note => !connectedNodeIds.has(note.id)).length;
}, [notes, edges]);
```

